import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Sidebar from "./Sidebar";
import Navbar from "./Navbar";
import "./Dashboard.css";
import {
    FaBuilding,
    FaUsers,
    FaFileContract,
    FaMoneyBillWave
} from "react-icons/fa";
import {
    Chart as ChartJS,
    ArcElement,
    Tooltip,
    Legend,
    CategoryScale,
    LinearScale,
    BarElement
} from "chart.js";

import { Pie, Bar } from "react-chartjs-2";

ChartJS.register(
    ArcElement,
    Tooltip,
    Legend,
    CategoryScale,
    LinearScale,
    BarElement
);

function Dashboard() {

    const [stats, setStats] = useState({
        properties: 0,
        tenants: 0,
        agreements: 0,
        payments: 0
    });

    useEffect(() => {
        fetchStats();
    }, []);

    const fetchStats = async () => {

        try {

            const token = localStorage.getItem("token");

            const response = await axios.get(
                "https://rental-management-system-backend-0h42.onrender.com/dashboard/stats",
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            );

            setStats(response.data);

        }
        catch (error) {

            console.log(error);

        }

    };

    const pieData = {
        labels: ["Payments", "Agreements"],
        datasets: [
            {
                data: [
                    stats.payments,
                    stats.agreements
                ],
                backgroundColor: [
                    "#36A2EB",
                    "#FFCE56"
                ]
            }
        ]
    };

    const barData = {
        labels: [
            "Properties",
            "Tenants",
            "Agreements",
            "Payments"
        ],
        datasets: [
            {
                label: "Count",
                data: [
                    stats.properties,
                    stats.tenants,
                    stats.agreements,
                    stats.payments
                ],
                backgroundColor: [
                    "#0d6efd",
                    "#198754",
                    "#ffc107",
                    "#0dcaf0"
                ]
            }
        ]
    };

    return (

        <>
            <Sidebar />

            <div className="dashboard-content">

                <Navbar />

                <div className="row mb-4">

                    <div className="col-md-3">

                        <div className="card stat-card bg-primary text-white">

                            <div className="card-body text-center">

                                <FaBuilding className="dashboard-icon" />

                                <h5>Properties</h5>

                                <h2>{stats.properties}</h2>

                            </div>

                        </div>

                    </div>

                    <div className="col-md-3">

                        <div className="card stat-card bg-success text-white">

                            <div className="card-body text-center">

                                <FaUsers className="dashboard-icon" />

                                <h5>Tenants</h5>

                                <h2>{stats.tenants}</h2>

                            </div>

                        </div>

                    </div>

                    <div className="col-md-3">

                        <div className="card stat-card bg-warning text-dark">

                            <div className="card-body text-center">

                                <FaFileContract className="dashboard-icon" />

                                <h5>Agreements</h5>

                                <h2>{stats.agreements}</h2>

                            </div>

                        </div>

                    </div>

                    <div className="col-md-3">

                        <div className="card stat-card bg-info text-white">

                            <div className="card-body text-center">

                                <FaMoneyBillWave className="dashboard-icon" />

                                <h5>Payments</h5>

                                <h2>{stats.payments}</h2>

                            </div>

                        </div>

                    </div>

                </div>

                <div className="row mb-5">

                    <div className="col-md-6">

                        <div className="chart-card">

                            <h4 className="mb-4 text-center">
                                Payment Distribution
                            </h4>

                            <Pie data={pieData} />

                        </div>

                    </div>

                    <div className="col-md-6">

                        <div className="chart-card">

                            <h4 className="mb-4 text-center">
                                Payment Summary
                            </h4>

                            <Bar data={barData} />

                        </div>

                    </div>

                </div>

                <div
                    style={{
                        marginTop: "50px",
                        textAlign: "center",
                        color: "#94a3b8"
                    }}
                >

                    <hr />

                    Rental Management System © 2026

                </div>

            </div>

        </>

    );

}

export default Dashboard;
